#!/usr/bin/env bash
# delete-unreferenced-images.sh
# Removes the 555 image files under /img/ that no HTML/CSS/JS/XML/JSON
# in the repo references. Freed: ~141 MB.
# Generated by the audit-fix pass on 2026-05-15.
#
# Usage:  bash scripts/delete-unreferenced-images.sh
# Review the file list below first if you want a diff. Each line is
# committed as a separate git delete, so `git status` after will show
# the same files in red and a single follow-up `git commit -am ...` is
# enough to record them.

set -e
cd "$(dirname "$0")/.."

deleted=0
freed=0
while IFS= read -r f; do
  [ -z "$f" ] && continue
  if [ -f "img/$f" ]; then
    sz=$(stat -f%z "img/$f" 2>/dev/null || stat -c%s "img/$f" 2>/dev/null || echo 0)
    git rm -q --cached -- "img/$f" 2>/dev/null || true
    rm -f -- "img/$f"
    deleted=$((deleted + 1))
    freed=$((freed + sz))
  fi
done <<'FILES'
